    /** Routes per-index getNet0/setNet0/... calls into $container. */
    public function __call(string $name, array $arguments)
    {

        if (preg_match('/^(get|set)Hostpci(\d+)$/', $name, $m)) {
            $verb = $m[1];
            $idx = (int) $m[2];
            if ($idx >= 0 && $idx <= 15) {
                $key = 'hostpci' . $idx;
                if ($verb === 'get') {
                    return $this->container[$key] ?? null;
                }
                $this->container[$key] = $arguments[0] ?? null;
                return $this;
            }
        }
        if (preg_match('/^(get|set)Ide(\d+)$/', $name, $m)) {
            $verb = $m[1];
            $idx = (int) $m[2];
            if ($idx >= 0 && $idx <= 3) {
                $key = 'ide' . $idx;
                if ($verb === 'get') {
                    return $this->container[$key] ?? null;
                }
                $this->container[$key] = $arguments[0] ?? null;
                return $this;
